INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07220', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那種有關社會團體工作的敘述是錯誤的？', '["社會團體工作的焦點在於「個人與環境的交流」，它不只牽涉個人內在行為的改變，同時亦關注到個 人社會功能的表現與環境對於個人需求的滿足", "團體組成的目的是以有利於服務對象的權益而不是以獲取機構或領導者的經驗為優先考量", "社會團體工作有很好的助人功能，因此其組成與運作並不需要以服務對象的最迫切的需求為前提，也 不用考慮成本效益的問題", "社會團體工作廣泛地運用於家庭服務、老人福利服務、兒童福利服務、青少年福利服務、醫療、企業、 身心障礙等機構及社區組織，實施範圍頗廣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07221', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體的組成是為了特定議題或單一主題的討論，它有一個主席主持討論的進行使討論聚焦而避免離題， 其組成目的包含確認需求與議題、提出可能的解決策略或計畫以及了解各種問題解決的策略可能產生的 後果等多種目的，這種團體稱為：', '["焦點團體", "自助團體", "教育團體", "治療團體"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07222', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社會工作者為精障者及愛滋病患做權益倡導及去汙名化的運動與活動，是屬於下列那一種社區工作的模 式？', '["地方發展", "社會計畫", "社會行動", "社區照顧"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07223', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '和社會工作實務有關的團體工作大致上可以分為兩類，即任務性團體與治療性團體，這兩類團體的運作 方式有其差異存在，以下那一個敘述並非是對任務性團體運作方式的描述？', '["溝通是聚焦在某一特殊任務與議題上", "團體中的成員的角色是可以被指定的", "鼓勵成員自我揭露情感的問題", "團體中的程序經常有正式的議程與規則安排"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07224', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依據下列那個社會團體工作理論，團體運作時，團體成員在團體中所表現出來的行為，被解釋為源自於 早期經驗沒有被解決的衝突，在許多情況下，團體會重新呈現家庭的情境，而團體的領導者被描述為像 是具有家庭最高權力形象的父親，其擁有至高無上的權威統治整個團體成員。成員會對領導者及其他成 員產生情感轉移的現象，此代表成員早期生活發展情況的呈現？', '["社會學習理論", "心理動力理論", "社會交換理論", "場域理論"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07225', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', 'Klein（1972）認為為了符合社會工作發展的宗旨，在協助個人適應環境中的人際關係和所遭遇的問題上， 團體工作有八個明確的目標。而透過團體工作運作的過程，來協助個人學習符合社會標準和人際關係技 巧，或協助那些已經退化而且需要再學習的人，乃是Klein（1972）所謂八個明確的目標的那一個目標？', '["矯正", "復健", "問題解決", "社會化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07226', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那些敘述並非是對於治療性團體的特質之描述？', '["團體成員通常會被期待要自我揭露自己的問題與關心的事情", "團體通常會由具有必要的資源與專長的成員組成", "團體運作的成功與否主要是看團體協助個人達成個人治療目標的程度", "團體的聚會經常是保密的"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07227', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者非屬於社會團體工作的類型？', '["教育性團體", "個案研討會", "成長團體", "支持性團體"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07228', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在領導一個團體成員是充滿興趣、熱忱且並未受到身心嚴重損傷的團體時，領導者宜採用下列那一種的 領導取向來領導團體會比較適當而有效？', '["團體領導者宜促進成員溝通、互動、了解和互助，鼓勵成員彼此間互相幫忙，而非將領導者視為解決 問題的專家", "以困擾或問題解決的專家，積極地介入團體為成員排解問題與困擾", "以充沛的精力，非常活躍的方式積極地提供服務給每一位團體成員", "以更為指導性與結構化的方式介入團體"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07229', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有一種力量是所有影響團體成員願意留在團體中的因素之總和，亦即吸引成員留在團體中的力量。當一 個團體運作時，其正向吸引力比負向吸引力的部分還要重要時，這種力量就會產生，這種力量我們稱為：', '["團體的正向思考力", "團體的凝聚力", "團體的充權力", "團體的行動力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
